<?php
// Start output buffering to prevent header HTML from breaking AJAX
ob_start(); 
include('header.php');

// --- AJAX HANDLER FOR STATUS TOGGLE ---
if (isset($_POST['action']) && $_POST['action'] == 'toggle_status') {
    // Clear any HTML generated by header.php so we send ONLY the number
    ob_clean(); 
    
    $sn = $_POST['sn'];
    $table = $_POST['table'];
    $current_status = $_POST['status'];
    
    // Toggle logic: If 1, make 0. If 0, make 1.
    $new_status = ($current_status == 1) ? 0 : 1;
    
    $allowed_tables = ['gametime_new', 'gametime_manual'];
    
    if (in_array($table, $allowed_tables)) {
        // Ensure $con (database connection) is available from header.php
        $updateQuery = "UPDATE `$table` SET `active`='$new_status' WHERE `sn`='$sn'";
        if (mysqli_query($con, $updateQuery)) {
            echo $new_status; // Send strictly "0" or "1"
        } else {
            echo "error";
        }
    }
    exit; // Stop the script here so no footer HTML is added
}
// Flush buffer if not AJAX
ob_end_flush(); 
?>

