        <?php
        function displayGames($con, $table_name, $start_count) {
            $count = $start_count;
            // Fetch games
            $query = "SELECT * FROM `$table_name` ORDER BY sn DESC"; 
            $result = mysqli_query($con, $query);

            while ($row = mysqli_fetch_assoc($result)) {
                $status = $row['active'];
                $btnClass = ($status == 1) ? '' : 'off';
                $btnText = ($status == 1) ? 'ON' : 'OFF';
                
                $openTime = date("h:i A", strtotime($row['open']));
                $closeTime = date("h:i A", strtotime($row['close']));
        ?>
            
            <div class="game-card">
                <div class="gc-left">
                    <div class="gc-sno"><?php echo str_pad($count, 2, '0', STR_PAD_LEFT); ?></div>
                    <div class="gc-info">
                        <span class="gc-name"><?php echo $row['market']; ?></span>
                        
                        <div class="gc-time-container">
                            <div class="time-row">
                                <span class="time-label">Open Time :</span>
                                <span class="time-value"><?php echo $openTime; ?></span>
                            </div>
                            <div class="time-row">
                                <span class="time-label">Close Time :</span>
                                <span class="time-value"><?php echo $closeTime; ?></span>
                            </div>
                        </div>

                    </div>
                </div>
                <div class="gc-right">
                    <button id="btn_<?php echo $row['sn']; ?>_<?php echo $table_name; ?>" 
                            class="toggle-btn <?php echo $btnClass; ?>" 
                            data-sn="<?php echo $row['sn']; ?>" 
                            data-table="<?php echo $table_name; ?>" 
                            data-status="<?php echo $status; ?>"
                            onclick="toggleGame(this)">
                        <?php echo $btnText; ?>
                    </button>
                </div>
            </div>

        <?php
                $count++;
            }
            return $count;
        }

        // Display Tables
        $next_count = 1;
        $next_count = displayGames($con, 'gametime_manual', $next_count);
        displayGames($con, 'gametime_new', $next_count);
