    <script src="https://code.jquery.com/jquery-3.6.0.min.js"></script>
    <script>
        function toggleGame(btn) {
            var $btn = $(btn);
            var sn = $btn.data('sn');
            var table = $btn.data('table');
            var currentStatus = $btn.data('status'); // 1 or 0

            // 1. Disable button momentarily to prevent double clicks
            $btn.prop('disabled', true).css('opacity', '0.7');

            // 2. Send Request
            $.ajax({
                url: window.location.href, // Post to self
                type: 'POST',
                data: {
                    action: 'toggle_status',
                    sn: sn,
                    table: table,
                    status: currentStatus
                },
                success: function(response) {
                    var cleanResponse = response.trim(); // Remove whitespace

                    // 3. Check if response is exactly '0' or '1'
                    if (cleanResponse === '0' || cleanResponse === '1') {
                        var newStatus = parseInt(cleanResponse);
                        
                        // Update Data Attribute for next click
                        $btn.data('status', newStatus);

                        // Update Visuals (Green/Red)
                        if (newStatus === 1) {
                            $btn.removeClass('off').text('ON'); // Turns Green
                        } else {
                            $btn.addClass('off').text('OFF'); // Turns Red
                        }
                    } else {
                        // If response is weird, log it
                        console.log("Error Response: " + response);
                        alert("Status update failed. Please refresh.");
                    }
                    $btn.prop('disabled', false).css('opacity', '1');
                },
                error: function() {
                    alert('Internet connection lost or server error.');
                    $btn.prop('disabled', false).css('opacity', '1');
                }
            });
        }
    </script>

